const responder = $('Fetch Responder Context').first()?.json || {};
const history = responder.history || {};
const contactStatus = history.contact_status || {};
const registryPayload = $('Build Intent Registry').first()?.json || {};
const valid = Array.isArray(registryPayload.validIntentKeys) ? registryPayload.validIntentKeys : [];
const intentMap = registryPayload.intentMap || {};
const fallbackIntent = registryPayload.fallbackIntent || 'discovery.program_detail';

const forcedRaw = contactStatus.forcedIntent || null;
const forced = typeof forcedRaw === 'string' ? forcedRaw.trim().toLowerCase() : null;
let classified = '';
if (!forced) {
  try {
    const raw = $('Intent Classifier').first()?.json?.text || '';
    classified = String(raw).trim().toLowerCase().replace(/[\s"'`]+/g, '');
  } catch (e) {
    classified = '';
  }
}

let selected = null;
let forcedApplied = false;
if (forced && valid.includes(forced)) {
  selected = forced;
  forcedApplied = true;
} else if (classified && valid.includes(classified)) {
  selected = classified;
} else {
  selected = fallbackIntent;
}

const meta = intentMap[selected] || {};
const conversationMode = contactStatus.conversationMode || $('Prepare Context').first()?.json?.conversation_mode || 'unknown';
const intentReplyMode = ['opening','mixed','continuation'].includes(meta.reply_mode) ? meta.reply_mode : 'continuation';
const classifierMatched = !!classified && classified === selected;
const useGreetingLlm = intentReplyMode === 'opening' && (forcedApplied || conversationMode !== 'continuation');

return [{
  json: {
    intent: selected,
    wasForced: !!forced,
    forcedApplied,
    forcedIntentRequested: forced,
    classifiedIntentRaw: classified || null,
    templateSubCategory: selected,
    useGreetingLlm,
    intentReplyMode,
    intentDescription: meta.description || '',
    taxonomySource: registryPayload.source || 'unknown',
    taxonomyRegistryCount: registryPayload.registry_count || valid.length || 0,
    intentFallbackUsed: !(forcedApplied || classifierMatched),
    fallbackIntentUsed: (selected === fallbackIntent) && !(forcedApplied || classifierMatched)
  }
}];

const ctx = $('Prepare Context').first().json;
const intentData = $('Merge Intent').first().json;
const responder = $('Fetch Responder Context').first().json || {};
const hist = responder.history || {};
const tplPayload = $input.first()?.json || {};
let templates = [];
if (Array.isArray(tplPayload.templates)) templates = tplPayload.templates;
else if (Array.isArray(tplPayload.data?.templates)) templates = tplPayload.data.templates;
else if (Array.isArray(tplPayload.items)) templates = tplPayload.items;
let templates_xml = 'Tidak ada template khusus. Gunakan gaya bahasa natural.';
if (templates.length > 0) {
  templates_xml = templates.map(t =>
    '<TEMPLATE name="' + (t.name||'') + '" intent="' + (t.sub_category||t.category||'general') + '">\n' + (t.content || '') + '\n</TEMPLATE>'
  ).join('\n\n');
}
return [{
  json: {
    ...ctx,
    intent: intentData.intent,
    wasForced: intentData.wasForced,
    forcedApplied: !!intentData.forcedApplied,
    useGreetingLlm: !!intentData.useGreetingLlm,
    template_sub_category: intentData.templateSubCategory || intentData.intent,
    intent_reply_mode: intentData.intentReplyMode || 'continuation',
    intent_description: intentData.intentDescription || '',
    taxonomy_source: intentData.taxonomySource || 'unknown',
    taxonomy_registry_count: intentData.taxonomyRegistryCount || null,
    intent_fallback_used: !!intentData.intentFallbackUsed,
    history: hist.history_text || '',
    time_context: hist.time_context || '',
    greeting_word: hist.greeting_word || '',
    prompt_instruction: hist.contact_status?.promptInstruction || '',
    conversation_mode: hist.contact_status?.conversationMode || ctx.conversation_mode || 'unknown',
    gap_since_previous_user_minutes: hist.contact_status?.gapMinutes ?? ctx.gap_minutes ?? null,
    templates_xml,
    templates_count: templates.length,
    template_fetch_error: tplPayload.error || tplPayload.message || null,
    rag_search_query: ctx.user_message,
    kb_type: 'faq'
  }
}];

