const taxonomyPayload = $('Fetch Template Taxonomy').first()?.json || {};

const fallbackRegistry = [
  { key: 'engagement.greeting_new', description: 'Sapaan untuk kontak baru yang pertama kali chat', reply_mode: 'opening' },
  { key: 'engagement.greeting_return', description: 'Sapaan untuk pelanggan lama yang kembali setelah lama tidak aktif', reply_mode: 'opening' },
  { key: 'engagement.time_inquiry', description: 'Pertanyaan jam operasional, ketersediaan slot, atau waktu layanan', reply_mode: 'mixed' },
  { key: 'discovery.program_detail', description: 'Permintaan penjelasan umum program atau jasa', reply_mode: 'continuation' },
  { key: 'discovery.schedule_location', description: 'Pertanyaan jadwal, lokasi, atau format online/offline', reply_mode: 'continuation' },
  { key: 'discovery.tutor_profile', description: 'Pertanyaan profil tim, pengajar, atau tenaga ahli', reply_mode: 'continuation' },
  { key: 'discovery.curriculum', description: 'Pertanyaan kurikulum, materi, metode, atau tahapan layanan', reply_mode: 'continuation' },
  { key: 'evaluation.pricing_inquiry', description: 'Pertanyaan harga atau paket tanpa keberatan harga', reply_mode: 'continuation' },
  { key: 'evaluation.objection_price', description: 'Keberatan harga mahal atau membandingkan value', reply_mode: 'continuation' },
  { key: 'evaluation.objection_compare', description: 'Perbandingan dengan kompetitor atau penyedia lain', reply_mode: 'continuation' },
  { key: 'evaluation.objection_risk', description: 'Kekhawatiran risiko, takut tidak cocok, atau takut rugi', reply_mode: 'continuation' },
  { key: 'evaluation.objection_authority', description: 'Keraguan kredibilitas, pengalaman, atau bukti hasil', reply_mode: 'continuation' },
  { key: 'evaluation.objection_urgency', description: 'Menunda keputusan, nanti dulu, atau masih pikir-pikir', reply_mode: 'continuation' },
  { key: 'conversion.soft', description: 'Ajakan lanjut lembut untuk prospek yang sudah tertarik', reply_mode: 'continuation' },
  { key: 'conversion.transaction', description: 'Instruksi pendaftaran, pembayaran, atau langkah transaksi', reply_mode: 'continuation' },
  { key: 'conversion.confirm', description: 'Konfirmasi pembayaran/pendaftaran dan langkah selanjutnya', reply_mode: 'continuation' },
  { key: 'retention.complaint_service', description: 'Keluhan layanan dan permintaan solusi terkait service', reply_mode: 'continuation' },
  { key: 'retention.complaint_refund', description: 'Permintaan refund atau pengembalian dana', reply_mode: 'continuation' },
  { key: 'retention.progress_inquiry', description: 'Pertanyaan progres atau status layanan yang sedang berjalan', reply_mode: 'continuation' },
  { key: 'retention.reschedule', description: 'Permintaan ubah jadwal, pindah slot, atau reschedule', reply_mode: 'continuation' },
];

const taxonomyIntents = Array.isArray(taxonomyPayload.intents)
  ? taxonomyPayload.intents
  : (Array.isArray(taxonomyPayload.subcategories) ? taxonomyPayload.subcategories : []);

let registry = taxonomyIntents
  .filter((i) => i && i.key && i.is_active !== false)
  .map((i) => ({
    key: String(i.key).trim().toLowerCase(),
    description: (i.description || i.label || 'No description provided').toString().trim(),
    reply_mode: ['opening', 'mixed', 'continuation'].includes(i.reply_mode) ? i.reply_mode : 'continuation',
    category_key: i.category_key || String(i.key).split('.')[0] || 'general',
    label: i.label || i.key,
  }))
  .filter((i) => i.key);

let source = 'taxonomy';
let taxonomyError = taxonomyPayload.error || taxonomyPayload.message || null;
if (registry.length === 0) {
  registry = fallbackRegistry;
  source = 'fallback-static';
}

const dedup = [];
const seen = new Set();
for (const item of registry) {
  if (seen.has(item.key)) continue;
  seen.add(item.key);
  dedup.push(item);
}
registry = dedup;

const validIntentKeys = registry.map((i) => i.key);
const intentMap = Object.fromEntries(registry.map((i) => [i.key, i]));
const preferredFallbacks = ['discovery.program_detail', 'discovery.schedule_location'];
let fallbackIntent = preferredFallbacks.find((k) => validIntentKeys.includes(k))
  || registry.find((i) => i.reply_mode === 'continuation')?.key
  || validIntentKeys[0]
  || 'discovery.program_detail';

const classifierIntentListText = registry
  .map((i) => '- ' + i.key + ' — ' + i.description + ' (mode: ' + i.reply_mode + ')')
  .join('\n');

return [{
  json: {
    source,
    taxonomy_error: taxonomyError,
    registry_count: registry.length,
    validIntentKeys,
    intentMap,
    fallbackIntent,
    classifierIntentListText,
    registry,
  }
}];

